import React, { useEffect, useRef, useState } from 'react';

const MIN_COLUMN_WIDTH = 120;

type ResizeState<T extends string> = {
  field: T;
  startX: number;
  startWidth: number;
};

const useResizableColumns = <T extends string>(initialWidths: Record<T, number>) => {
  const [columnWidths, setColumnWidths] = useState<Record<T, number>>(initialWidths);
  const resizeStateRef = useRef<ResizeState<T> | null>(null);

  useEffect(() => {
    const handleMouseMove = (event: MouseEvent) => {
      const resizeState = resizeStateRef.current;
      if (!resizeState) return;

      const nextWidth = Math.max(MIN_COLUMN_WIDTH, resizeState.startWidth + event.clientX - resizeState.startX);
      setColumnWidths((prev) => ({
        ...prev,
        [resizeState.field]: nextWidth,
      }));
    };

    const handleMouseUp = () => {
      if (!resizeStateRef.current) return;
      resizeStateRef.current = null;
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    };
  }, []);

  const startColumnResize = (field: T, event: React.MouseEvent<HTMLSpanElement>) => {
    event.preventDefault();
    event.stopPropagation();

    const headerCell = event.currentTarget.closest('th') as HTMLTableCellElement | null;
    resizeStateRef.current = {
      field,
      startX: event.clientX,
      startWidth: columnWidths[field] || headerCell?.getBoundingClientRect().width || MIN_COLUMN_WIDTH,
    };
    document.body.style.cursor = 'col-resize';
    document.body.style.userSelect = 'none';
  };

  const getColumnStyle = (field: T): React.CSSProperties => ({
    width: columnWidths[field],
    minWidth: columnWidths[field],
  });

  const renderResizeHandle = (field: T) => (
    <span
      role="separator"
      aria-orientation="vertical"
      aria-label="Resize column"
      onMouseDown={(event) => startColumnResize(field, event)}
      className="absolute right-0 top-0 h-full w-2 cursor-col-resize touch-none select-none border-r border-transparent hover:border-blue-400"
    />
  );

  return {
    getColumnStyle,
    renderResizeHandle,
  };
};

export default useResizableColumns;
